sp_widget.client_script:
api.controller=function() {
  /* widget controller */
  var c = this;
};

sp_widget.css:
.my-requests{

    padding:60px;
    background:#f5f7fa;
    min-height:100vh;

}

.my-requests h1{

    text-align:center;
    color:#0F4C81;

}

.subtitle{

    text-align:center;
    margin-bottom:40px;
    color:#666;

}

.toolbar{

    display:flex;
    justify-content:space-between;
    margin-bottom:25px;
    flex-wrap:wrap;
    gap:15px;

}

.toolbar input{

    width:320px;
    padding:12px;
    border:1px solid #ccc;
    border-radius:6px;

}

.toolbar select{

    padding:12px;
    border:1px solid #ccc;
    border-radius:6px;

}

.request-table{

    width:100%;
    border-collapse:collapse;
    background:white;
    box-shadow:0 8px 18px rgba(0,0,0,.08);

}

.request-table th{

    background:#0F4C81;
    color:white;
    padding:15px;

}

.request-table td{

    padding:15px;
    border-bottom:1px solid #eee;

}

.request-table tr:hover{

    background:#f8f9fc;

}

.status{

    padding:6px 14px;
    border-radius:20px;
    color:white;
    font-weight:bold;
    font-size:13px;

}

.pending{

    background:#f39c12;

}

.approved{

    background:#27ae60;

}

.completed{

    background:#2980b9;

}

.rejected{

    background:#e74c3c;

}

sp_widget.script:
(function() {

    data.requests = [];

    var gr = new GlideRecord('x_1958816_enterp_0_network_request');
    gr.query();

    while (gr.next()) {

        data.requests.push({
            number: gr.getValue('number'),
            request_type: gr.getDisplayValue('request_type'),
            priority: gr.getDisplayValue('priority'),
            state: gr.getDisplayValue('state')
        });

    }

})();
